import { buildCanonicalData, MOCK_DATA_VERSION } from './canonical-data.js'

const STORE_KEY = '__tea_mall_mock_store__'
const SESSION_KEY = '__tea_mall_mock_sessions__'
const ACTIVE_ORDER_STATUSES = ['已支付', '已发货', '已完成']

function clone(value) {
  return JSON.parse(JSON.stringify(value))
}

function safeParse(value, fallback) {
  try {
    return value ? JSON.parse(value) : fallback
  } catch (error) {
    return fallback
  }
}

function nowDateTime() {
  const date = new Date()
  const pad = function (value) {
    return String(value).padStart(2, '0')
  }
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())} ${pad(date.getHours())}:${pad(date.getMinutes())}:${pad(date.getSeconds())}`
}

function createMockUploadUrl() {
  const svg = [
    '<svg xmlns="http://www.w3.org/2000/svg" width="240" height="240" viewBox="0 0 240 240">',
    '<rect width="240" height="240" fill="#f4f5f7"/>',
    '<rect x="24" y="24" width="192" height="192" rx="16" fill="#ffffff" stroke="#d9dce3" stroke-dasharray="8 8"/>',
    '<text x="120" y="110" text-anchor="middle" font-size="18" fill="#7a8291">Mock Upload</text>',
    '<text x="120" y="138" text-anchor="middle" font-size="12" fill="#9aa1ad">No image asset required</text>',
    '</svg>'
  ].join('')
  return `data:image/svg+xml;charset=UTF-8,${encodeURIComponent(svg)}`
}

function normalizeUrl(rawUrl) {
  let url = rawUrl || ''
  if (url.indexOf('://') !== -1) {
    const withoutHost = url.replace(/^https?:\/\/[^/]+/i, '')
    url = withoutHost || url
  }
  const queryIndex = url.indexOf('?')
  const queryString = queryIndex >= 0 ? url.slice(queryIndex + 1) : ''
  let path = queryIndex >= 0 ? url.slice(0, queryIndex) : url
  path = path.replace(/^\/+/, '')
  path = path.replace(/^springbooty2rp6\/?/, '')
  return {
    path,
    queryString
  }
}

function parseQueryString(queryString) {
  if (!queryString) {
    return {}
  }
  return queryString.split('&').reduce(function (result, pair) {
    const parts = pair.split('=')
    const key = decodeURIComponent(parts[0] || '')
    if (!key) {
      return result
    }
    result[key] = decodeURIComponent(parts[1] || '')
    return result
  }, {})
}

function loadState(storage) {
  const parsed = safeParse(storage.getItem(STORE_KEY), null)
  if (!parsed || parsed.version !== MOCK_DATA_VERSION) {
    const seeded = {
      version: MOCK_DATA_VERSION,
      data: buildCanonicalData()
    }
    storage.setItem(STORE_KEY, JSON.stringify(seeded))
    return seeded
  }
  return parsed
}

function saveState(storage, state) {
  storage.setItem(STORE_KEY, JSON.stringify(state))
}

function loadSessions(storage) {
  return safeParse(storage.getItem(SESSION_KEY), {})
}

function saveSessions(storage, sessions) {
  storage.setItem(SESSION_KEY, JSON.stringify(sessions))
}

function nextId(list) {
  return list.reduce(function (maxValue, item) {
    return Math.max(maxValue, Number(item.id) || 0)
  }, 0) + 1
}

function getLoginMeta(tableName) {
  if (tableName === 'users') {
    return { usernameKey: 'username', passwordKey: 'password' }
  }
  if (tableName === 'yonghu') {
    return { usernameKey: 'yonghuming', passwordKey: 'mima' }
  }
  if (tableName === 'shangjia') {
    return { usernameKey: 'zhanghao', passwordKey: 'mima' }
  }
  return null
}

function getRecordName(record, tableName) {
  const meta = getLoginMeta(tableName)
  return meta ? record[meta.usernameKey] : ''
}

function createToken(tableName, record) {
  return `${tableName}-${record.id}-${Date.now()}`
}

function resolveSession(storage, headers) {
  const sessions = loadSessions(storage)
  const token = (headers && (headers.Token || headers.token)) || storage.getItem('Token')
  if (token && sessions[token]) {
    return sessions[token]
  }

  const fallbackTable = storage.getItem('sessionTable') || storage.getItem('UserTableName')
  const fallbackName = storage.getItem('adminName') || storage.getItem('username')
  if (!fallbackTable || !fallbackName) {
    return null
  }

  return {
    tableName: fallbackTable,
    username: fallbackName,
    userId: Number(storage.getItem('userid')) || null
  }
}

function getCurrentRecord(state, session) {
  if (!session || !state.data[session.tableName]) {
    return null
  }
  const meta = getLoginMeta(session.tableName)
  const list = state.data[session.tableName]
  if (session.userId) {
    const foundById = list.find(function (item) {
      return Number(item.id) === Number(session.userId)
    })
    if (foundById) {
      return foundById
    }
  }
  if (!meta) {
    return null
  }
  return list.find(function (item) {
    return String(item[meta.usernameKey]) === String(session.username)
  }) || null
}

function toNumber(value) {
  const numeric = Number(value)
  return Number.isNaN(numeric) ? 0 : numeric
}

function getFieldValue(record, key) {
  if (key === 'algorithmType') {
    return record.algorithmType || record.algorithm_type
  }
  if (key === 'createTime') {
    return record.createTime || record.create_time
  }
  return record[key]
}

function matchesLike(recordValue, searchValue) {
  return String(recordValue || '').toLowerCase().indexOf(String(searchValue || '').toLowerCase()) !== -1
}

function filterRecords(records, params) {
  const ignoredKeys = {
    page: true,
    limit: true,
    sort: true,
    order: true,
    __body: true
  }

  return records.filter(function (record) {
    return Object.keys(params || {}).every(function (key) {
      if (ignoredKeys[key] || params[key] === undefined || params[key] === null || params[key] === '') {
        return true
      }

      const expected = params[key]
      const actual = getFieldValue(record, key)

      if (key === 'pricestart') {
        return toNumber(record.price) >= toNumber(expected)
      }
      if (key === 'priceend') {
        return toNumber(record.price) <= toNumber(expected)
      }
      if (typeof expected === 'string' && expected.startsWith('%') && expected.endsWith('%')) {
        return matchesLike(actual, expected.slice(1, -1))
      }
      return String(actual) === String(expected)
    })
  })
}

function sortRecords(records, sortField, order) {
  const direction = String(order || 'asc').toLowerCase() === 'desc' ? -1 : 1
  const field = sortField || 'id'
  return records.slice().sort(function (left, right) {
    const leftValue = getFieldValue(left, field)
    const rightValue = getFieldValue(right, field)
    if (leftValue === rightValue) {
      return 0
    }
    if (leftValue === undefined || leftValue === null) {
      return -1 * direction
    }
    if (rightValue === undefined || rightValue === null) {
      return 1 * direction
    }
    return leftValue > rightValue ? direction : -1 * direction
  })
}

function paginate(records, page, limit) {
  const currentPage = Math.max(1, toNumber(page) || 1)
  const pageSize = Math.max(1, toNumber(limit) || 10)
  const start = (currentPage - 1) * pageSize
  const list = records.slice(start, start + pageSize)
  return {
    list,
    total: records.length,
    pageSize,
    currPage: currentPage,
    totalPage: Math.max(1, Math.ceil(records.length / pageSize))
  }
}

function tableScopeFilter(tableName, records, session, state, params) {
  if (!session) {
    return records
  }

  if (session.tableName === 'yonghu') {
    const userId = Number(session.userId)
    if ((tableName === 'address' || tableName === 'cart' || tableName === 'storeup' || tableName === 'orders') && !params.userid) {
      return records.filter(function (item) {
        return Number(item.userid) === userId
      })
    }
  }

  if (session.tableName === 'shangjia') {
    if (tableName === 'shangpinxinxi' && !params.zhanghao) {
      return records.filter(function (item) {
        return item.zhanghao === session.username
      })
    }
    if ((tableName === 'teabase' || tableName === 'teabatch' || tableName === 'inventoryrecord') && !params.enterpriseaccount) {
      return records.filter(function (item) {
        return item.enterpriseaccount === session.username
      })
    }
    if (tableName === 'orders' && !params.zhanghao) {
      return records.filter(function (item) {
        return item.zhanghao === session.username
      })
    }
    if (tableName === 'recommendation') {
      const ownedProductIds = state.data.shangpinxinxi
        .filter(function (item) { return item.zhanghao === session.username })
        .map(function (item) { return item.id })
      return records.filter(function (item) {
        return ownedProductIds.indexOf(item.goodid) !== -1
      })
    }
  }

  return records
}

function success(data, msg) {
  return {
    code: 0,
    data: data === undefined ? null : data,
    msg: msg || 'success'
  }
}

function failure(msg, code) {
  return {
    code: code || 500,
    msg: msg || 'mock error'
  }
}

function enrichRecommendations(state, items) {
  return items.map(function (item) {
    const product = state.data.shangpinxinxi.find(function (current) {
      return Number(current.id) === Number(item.goodid)
    }) || {}
    return Object.assign({}, product, {
      id: item.id,
      goodid: item.goodid,
      userid: item.userid,
      score: item.score,
      reason: item.reason,
      algorithmType: item.algorithmType,
      createTime: item.createTime
    })
  })
}

function rebuildRecommendationsForUser(state, userId) {
  const orders = state.data.orders.filter(function (item) {
    return Number(item.userid) === Number(userId)
  })
  const storeup = state.data.storeup.filter(function (item) {
    return Number(item.userid) === Number(userId)
  })
  const scores = {}

  orders.forEach(function (item) {
    scores[item.goodtype] = (scores[item.goodtype] || 0) + 3
  })
  storeup.forEach(function (item) {
    scores[item.inteltype] = (scores[item.inteltype] || 0) + 2
  })

  const orderedCategories = Object.keys(scores).sort(function (left, right) {
    return scores[right] - scores[left]
  })
  const preferred = orderedCategories.length ? orderedCategories : [state.data.shangpinfenlei[0].shangpinfenlei]

  state.data.recommendation = state.data.recommendation.filter(function (item) {
    return Number(item.userid) !== Number(userId)
  })

  const candidates = state.data.shangpinxinxi.filter(function (item) {
    return preferred.indexOf(item.shangpinfenlei) !== -1
  }).slice(0, 8)

  candidates.forEach(function (product, index) {
    state.data.recommendation.push({
      id: nextId(state.data.recommendation),
      userid: Number(userId),
      goodid: product.id,
      score: Number((1.45 - index * 0.12).toFixed(4)),
      reason: index === 0 ? '结合收藏与下单行为优先推荐' : `偏好分类 ${product.shangpinfenlei} 的延伸推荐`,
      algorithmType: 'hybrid',
      createTime: nowDateTime()
    })
  })
}

function refreshAllRecommendations(state) {
  const userIds = state.data.yonghu.map(function (item) { return item.id })
  state.data.recommendation = []
  userIds.forEach(function (userId) {
    rebuildRecommendationsForUser(state, userId)
  })
}

function parsePath(path) {
  return path.split('/').filter(Boolean)
}

function buildSalesTrend(records) {
  const map = {}
  const now = new Date()
  for (let offset = 5; offset >= 0; offset -= 1) {
    const date = new Date(now.getFullYear(), now.getMonth() - offset, 1)
    const key = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`
    map[key] = { monthKey: key, label: `${date.getMonth() + 1}月`, sales: 0, revenue: 0 }
  }

  records.forEach(function (item) {
    const key = String(item.addtime || '').slice(0, 7)
    if (!map[key]) {
      return
    }
    map[key].sales += Number(item.buynumber) || 0
    map[key].revenue += Number(item.total) || 0
  })

  return Object.keys(map).sort().map(function (key) {
    const item = map[key]
    item.revenue = Number(item.revenue.toFixed(2))
    return item
  })
}

function buildDecisionData(state, session) {
  const enterpriseAccount = session && session.tableName === 'shangjia' ? session.username : ''
  const orderRecords = state.data.orders.filter(function (item) {
    if (ACTIVE_ORDER_STATUSES.indexOf(item.status) === -1) {
      return false
    }
    if (enterpriseAccount) {
      return item.zhanghao === enterpriseAccount
    }
    return true
  })

  const products = state.data.shangpinxinxi.filter(function (item) {
    return enterpriseAccount ? item.zhanghao === enterpriseAccount : true
  })
  const bases = state.data.teabase.filter(function (item) {
    return enterpriseAccount ? item.enterpriseaccount === enterpriseAccount : true
  })
  const inventory = state.data.inventoryrecord.filter(function (item) {
    return enterpriseAccount ? item.enterpriseaccount === enterpriseAccount : true
  })

  const latestInventoryByBatch = {}
  inventory.forEach(function (item) {
    const existing = latestInventoryByBatch[item.batchcode]
    if (!existing || String(existing.addtime) < String(item.addtime)) {
      latestInventoryByBatch[item.batchcode] = item
    }
  })

  const latestInventory = Object.keys(latestInventoryByBatch).map(function (key) {
    return latestInventoryByBatch[key]
  })

  const topProductsMap = {}
  orderRecords.forEach(function (item) {
    topProductsMap[item.goodname] = (topProductsMap[item.goodname] || 0) + Number(item.buynumber)
  })
  const topProducts = Object.keys(topProductsMap).map(function (name) {
    return { name, value: topProductsMap[name] }
  }).sort(function (left, right) {
    return right.value - left.value
  }).slice(0, 5)

  const categoryShareMap = {}
  orderRecords.forEach(function (item) {
    categoryShareMap[item.goodtype] = (categoryShareMap[item.goodtype] || 0) + Number(item.buynumber)
  })
  const categoryShare = Object.keys(categoryShareMap).map(function (name) {
    return { name, value: categoryShareMap[name] }
  }).sort(function (left, right) {
    return right.value - left.value
  }).slice(0, 6)

  const forecastList = products.slice(0, 12).map(function (product, index) {
    const recentSales = orderRecords
      .filter(function (item) { return Number(item.goodid) === Number(product.id) })
      .reduce(function (sum, item) { return sum + Number(item.buynumber); }, 0)
    const dailyAverage = recentSales / 7 || ((index % 5) + 1) * 0.8
    const forecast7Days = Math.max(3, Math.round(dailyAverage * 7))
    return {
      productId: product.id,
      productName: product.shangpinmingcheng,
      category: product.shangpinfenlei,
      recentSales,
      dailyAverage: Number(dailyAverage.toFixed(2)),
      forecast3Days: Math.max(1, Math.round(dailyAverage * 3)),
      forecast7Days,
      trend: recentSales % 3 === 0 ? 'up' : (recentSales % 2 === 0 ? 'steady' : 'down')
    }
  })

  const inventoryRiskList = latestInventory.slice(0, 10).map(function (item) {
    const currentStock = Number(item.currentstock) || 0
    const warningStock = Number(item.warningstock) || 0
    const availableDays = currentStock / Math.max(1, warningStock / 3)
    let riskLevel = 'safe'
    if (currentStock <= warningStock * 0.8) {
      riskLevel = 'urgent'
    } else if (currentStock <= warningStock * 1.1) {
      riskLevel = 'warning'
    } else if (currentStock <= warningStock * 1.6) {
      riskLevel = 'attention'
    }
    return {
      batchCode: item.batchcode,
      productName: item.productname,
      category: (state.data.shangpinxinxi.find(function (product) {
        return product.shangpinmingcheng === item.productname
      }) || {}).shangpinfenlei || '未分类',
      currentStock,
      warningStock,
      availableDays: Number(availableDays.toFixed(2)),
      riskLevel,
      riskScore: Number((warningStock === 0 ? 0 : (warningStock / Math.max(currentStock, 1)) * 100).toFixed(2)),
      warningReason: currentStock <= warningStock ? '当前库存已低于预警线' : '库存接近预警线'
    }
  })

  const restockPlanList = forecastList.slice(0, 8).map(function (item) {
    const matchingInventory = inventoryRiskList.find(function (risk) {
      return risk.productName === item.productName
    })
    const currentStock = matchingInventory ? matchingInventory.currentStock : 45
    const safetyStock = Math.max(20, Math.round(item.forecast7Days * 0.6))
    const suggestedRestock = Math.max(0, safetyStock + item.forecast7Days - currentStock)
    let priority = 'low'
    if (suggestedRestock >= 60) {
      priority = 'urgent'
    } else if (suggestedRestock >= 35) {
      priority = 'high'
    } else if (suggestedRestock >= 15) {
      priority = 'medium'
    }
    return {
      productName: item.productName,
      category: item.category,
      currentStock,
      safetyStock,
      forecast7Days: item.forecast7Days,
      suggestedRestock,
      suggestedDays: 7,
      priority,
      reason: suggestedRestock > 0 ? '预测销量高于当前安全库存，建议提前补货。' : '现有库存可以覆盖短期需求。'
    }
  })

  const forecastSummary = {
    totalForecast7Days: forecastList.reduce(function (sum, item) {
      return sum + Number(item.forecast7Days)
    }, 0),
    topProductName: forecastList[0] ? forecastList[0].productName : '暂无预测',
    topForecast7Days: forecastList[0] ? forecastList[0].forecast7Days : 0
  }

  const adviceList = [
    {
      level: inventoryRiskList.some(function (item) { return item.riskLevel === 'urgent' }) ? 'danger' : 'success',
      title: '库存调度',
      content: inventoryRiskList.some(function (item) { return item.riskLevel === 'urgent' })
        ? '部分批次库存已经低于预警线，建议优先执行紧急补货。'
        : '当前库存整体稳定，可继续按节奏推进备货计划。',
      actionLabel: '优先检查低库存批次'
    },
    {
      level: 'info',
      title: '品类经营',
      content: categoryShare[0]
        ? `当前销量占比最高的品类为 ${categoryShare[0].name}，可加大首页与活动曝光。`
        : '暂无明显主力品类，建议继续积累销售数据。',
      actionLabel: '优化主力品类投放'
    },
    {
      level: restockPlanList.some(function (item) { return item.priority === 'urgent' || item.priority === 'high' }) ? 'warning' : 'success',
      title: '补货建议',
      content: restockPlanList.some(function (item) { return item.suggestedRestock > 0 })
        ? '已有商品触发补货建议，建议结合供应周期提前锁定批次。'
        : '短期内库存可满足预测销量，无需额外补货。',
      actionLabel: '同步采购与仓储排期'
    }
  ]

  const stats = {
    enterpriseCount: enterpriseAccount ? 1 : state.data.shangjia.length,
    baseCount: bases.length,
    productCount: products.length,
    orderCount: orderRecords.length,
    currentMonthSales: buildSalesTrend(orderRecords).slice(-1)[0].sales || 0,
    currentMonthRevenue: buildSalesTrend(orderRecords).slice(-1)[0].revenue || 0,
    lastMonthSales: buildSalesTrend(orderRecords).slice(-2)[0] ? buildSalesTrend(orderRecords).slice(-2)[0].sales : 0,
    lastMonthRevenue: buildSalesTrend(orderRecords).slice(-2)[0] ? buildSalesTrend(orderRecords).slice(-2)[0].revenue : 0,
    inventoryWarningCount: inventoryRiskList.filter(function (item) { return item.riskLevel !== 'safe' }).length,
    slowMovingProductCount: products.filter(function (product) {
      return !orderRecords.some(function (order) { return order.goodid === product.id })
    }).length,
    abnormalEnterpriseCount: enterpriseAccount ? 0 : 2,
    forecast7DaysTotal: forecastSummary.totalForecast7Days,
    highRiskProductCount: inventoryRiskList.filter(function (item) { return item.riskLevel === 'urgent' || item.riskLevel === 'warning' }).length,
    restockPendingCount: restockPlanList.filter(function (item) { return item.suggestedRestock > 0 }).length
  }

  return {
    stats,
    salesTrend: buildSalesTrend(orderRecords),
    categoryShare,
    topProducts,
    topEnterprises: [],
    lowStockList: inventoryRiskList.map(function (item) {
      return {
        productName: item.productName,
        batchCode: item.batchCode,
        currentStock: item.currentStock,
        warningStock: item.warningStock
      }
    }).slice(0, 6),
    forecastList,
    inventoryRiskList,
    restockPlanList,
    forecastSummary,
    restockPendingCount: stats.restockPendingCount,
    adviceList
  }
}

function handleOption(state, segments) {
  const tableName = segments[1]
  const fieldName = segments[2]
  const list = state.data[tableName] || []
  const values = list
    .map(function (item) { return item[fieldName] })
    .filter(function (item, index, arr) { return item !== undefined && item !== '' && arr.indexOf(item) === index })
  return success(values)
}

function handleLogin(state, storage, segments, params, headers) {
  const tableName = segments[0]
  const meta = getLoginMeta(tableName)
  if (!meta) {
    return failure('不支持的登录类型')
  }
  const list = state.data[tableName] || []
  const username = params.username
  const password = params.password
  const record = list.find(function (item) {
    return String(item[meta.usernameKey]) === String(username) && String(item[meta.passwordKey]) === String(password)
  })
  if (!record) {
    return failure('账号或密码错误')
  }
  const token = createToken(tableName, record)
  const sessions = loadSessions(storage)
  sessions[token] = {
    tableName,
    userId: record.id,
    username: record[meta.usernameKey]
  }
  saveSessions(storage, sessions)
  return {
    code: 0,
    token,
    msg: 'success'
  }
}

function handleRegister(state, storage, segments, body) {
  const tableName = segments[0]
  const meta = getLoginMeta(tableName)
  const list = state.data[tableName]
  if (!meta || !list) {
    return failure('不支持的注册类型')
  }
  const username = body[meta.usernameKey]
  if (!username) {
    return failure('缺少账号')
  }
  const exists = list.some(function (item) {
    return String(item[meta.usernameKey]) === String(username)
  })
  if (exists) {
    return failure('账号已存在')
  }
  const record = Object.assign({
    id: nextId(list),
    addtime: nowDateTime()
  }, body)
  if (tableName === 'yonghu') {
    record.vip = record.vip || '否'
    record.money = toNumber(record.money || 500)
    record.touxiang = record.touxiang || ''
  }
  if (tableName === 'shangjia') {
    record.money = toNumber(record.money || 3000)
    record.touxiang = record.touxiang || ''
  }
  list.unshift(record)
  saveState(storage, state)
  return success(null, '注册成功')
}

function handleSession(state, storage, segments, headers) {
  const requestedTable = segments[0]
  const session = resolveSession(storage, headers)
  const record = getCurrentRecord(state, session)
  if (!record || session.tableName !== requestedTable) {
    return failure('未登录', 401)
  }
  return success(clone(record))
}

function handleGenericList(state, storage, tableName, params, headers) {
  const session = resolveSession(storage, headers)
  const baseList = state.data[tableName] || []
  const scoped = tableScopeFilter(tableName, baseList, session, state, params)
  const filtered = filterRecords(scoped, params)
  const sorted = sortRecords(filtered, params.sort, params.order)
  return success(paginate(sorted, params.page, params.limit))
}

function handleGenericDetail(state, tableName, id) {
  const record = (state.data[tableName] || []).find(function (item) {
    return Number(item.id) === Number(id)
  })
  return record ? success(clone(record)) : failure('记录不存在', 404)
}

function handleGenericSave(state, storage, tableName, body) {
  const list = state.data[tableName]
  if (!list) {
    return failure('不支持的数据表')
  }
  const record = Object.assign({
    id: nextId(list),
    addtime: nowDateTime()
  }, clone(body))
  list.unshift(record)
  saveState(storage, state)
  return success(null)
}

function handleGenericUpdate(state, storage, tableName, body) {
  const list = state.data[tableName]
  if (!list) {
    return failure('不支持的数据表')
  }
  const index = list.findIndex(function (item) {
    return Number(item.id) === Number(body.id)
  })
  if (index === -1) {
    return failure('记录不存在', 404)
  }
  list[index] = Object.assign({}, list[index], clone(body))
  saveState(storage, state)
  return success(null)
}

function handleGenericDelete(state, storage, tableName, body) {
  const list = state.data[tableName]
  if (!list) {
    return failure('不支持的数据表')
  }
  const ids = Array.isArray(body) ? body.map(Number) : [Number(body)]
  state.data[tableName] = list.filter(function (item) {
    return ids.indexOf(Number(item.id)) === -1
  })
  saveState(storage, state)
  return success(null)
}

function handleRecommendation(state, storage, segments, method, params, headers) {
  const session = resolveSession(storage, headers)

  if (segments[1] === 'user' && segments[2] === 'list') {
    const currentUserId = session && session.tableName === 'yonghu' ? session.userId : Number(storage.getItem('userid')) || state.data.yonghu[0].id
    const userItems = state.data.recommendation
      .filter(function (item) { return Number(item.userid) === Number(currentUserId) })
      .sort(function (left, right) { return Number(right.score) - Number(left.score) })
      .slice(0, toNumber(params.limit) || 20)
    return success(enrichRecommendations(state, userItems))
  }

  if (segments[1] === 'refresh' && segments[2] === 'all') {
    refreshAllRecommendations(state)
    saveState(storage, state)
    return success(null)
  }

  if (segments[1] === 'refresh') {
    const currentUserId = session && session.tableName === 'yonghu' ? session.userId : Number(storage.getItem('userid')) || state.data.yonghu[0].id
    rebuildRecommendationsForUser(state, currentUserId)
    saveState(storage, state)
    return success(null)
  }

  if (segments[1] === 'page' || segments[1] === 'list') {
    return handleGenericList(state, storage, 'recommendation', params, headers)
  }

  if (segments[1] === 'info') {
    return handleGenericDetail(state, 'recommendation', segments[2])
  }

  if (segments[1] === 'delete') {
    return handleGenericDelete(state, storage, 'recommendation', params.__body || [])
  }

  return failure('未实现的 recommendation 接口', 404)
}

function groupOrdersBy(orderRecords, fieldName, metric, period) {
  const map = {}
  orderRecords.forEach(function (item) {
    let key = item[fieldName]
    if (fieldName === 'addtime') {
      const rawDate = String(item.addtime || '').slice(0, 10)
      if (period === '月') {
        key = rawDate.slice(0, 7)
      } else if (period === '年') {
        key = rawDate.slice(0, 4)
      } else {
        key = rawDate
      }
    }
    if (!key) {
      return
    }
    map[key] = map[key] || { [fieldName]: key, buynumber: 0, total: 0 }
    map[key].buynumber += Number(item.buynumber) || 0
    map[key].total += Number(item.total) || 0
  })
  return Object.keys(map).sort().map(function (key) {
    const item = map[key]
    item.total = Number(item.total.toFixed(2))
    return item
  })
}

function handleOrdersValue(state, storage, segments, headers) {
  const session = resolveSession(storage, headers)
  const enterpriseAccount = session && session.tableName === 'shangjia' ? session.username : ''
  const filteredOrders = state.data.orders.filter(function (item) {
    if (item.status !== '已完成') {
      return false
    }
    return enterpriseAccount ? item.zhanghao === enterpriseAccount : true
  })
  const fieldName = segments[2]
  const metric = segments[3]
  const period = segments[4]
  return success(groupOrdersBy(filteredOrders, fieldName, metric, period))
}

function handleOrdersShip(state, storage, body, headers) {
  const session = resolveSession(storage, headers)
  const order = state.data.orders.find(function (item) {
    return Number(item.id) === Number(body.id)
  })
  if (!order) {
    return failure('订单不存在', 404)
  }
  if (!body.logistics || !String(body.logistics).trim()) {
    return failure('请填写物流信息')
  }
  if (session && session.tableName === 'shangjia' && order.zhanghao !== session.username) {
    return failure('无权发货该订单', 403)
  }
  if (order.status !== '已支付') {
    return failure('只有已支付订单可以发货')
  }
  order.logistics = String(body.logistics).trim()
  order.status = '已发货'
  saveState(storage, state)
  return success(null)
}

function handleDecision(state, storage, segments, headers) {
  const session = resolveSession(storage, headers)
  const data = buildDecisionData(state, session || { tableName: 'users' })
  if (segments[1] === 'dashboard') {
    return success(data)
  }
  if (segments[1] === 'advice') {
    return success(data.adviceList)
  }
  if (segments[1] === 'forecast') {
    return success(data.forecastList)
  }
  if (segments[1] === 'inventory-risk') {
    return success(data.inventoryRiskList)
  }
  if (segments[1] === 'restock-plan') {
    return success(data.restockPlanList)
  }
  return failure('未实现的 decision 接口', 404)
}

function handleFileUpload() {
  return {
    code: 0,
    file: '',
    url: createMockUploadUrl(),
    msg: 'success'
  }
}

function prepareRequestBody(config) {
  if (config.data !== undefined) {
    return config.data
  }
  return {}
}

export function handleMockRequest(config, options) {
  const storage = options && options.storage ? options.storage : window.localStorage
  const normalized = normalizeUrl(config.url)
  const queryParams = parseQueryString(normalized.queryString)
  const params = Object.assign({}, queryParams, config.params || {})
  const body = prepareRequestBody(config)
  params.__body = body

  const state = loadState(storage)
  const segments = parsePath(normalized.path)
  const method = String(config.method || 'get').toLowerCase()
  const headers = Object.assign({}, (options && options.headers) || {}, config.headers || {})

  if (!segments.length) {
    return failure('空请求路径', 404)
  }

  if (segments[0] === 'file' && segments[1] === 'upload') {
    return handleFileUpload()
  }
  if (segments[0] === 'option') {
    return handleOption(state, segments)
  }
  if (segments[0] === 'decision') {
    return handleDecision(state, storage, segments, headers)
  }
  if (segments[0] === 'recommendation') {
    return handleRecommendation(state, storage, segments, method, params, headers)
  }
  if (segments[0] === 'orders' && segments[1] === 'value') {
    return handleOrdersValue(state, storage, segments, headers)
  }
  if (segments[0] === 'orders' && segments[1] === 'ship') {
    return handleOrdersShip(state, storage, body, headers)
  }
  if (segments[1] === 'login') {
    return handleLogin(state, storage, segments, params, headers)
  }
  if (segments[1] === 'register') {
    return handleRegister(state, storage, segments, body)
  }
  if (segments[1] === 'session') {
    return handleSession(state, storage, segments, headers)
  }
  if (segments[1] === 'page' || segments[1] === 'list') {
    return handleGenericList(state, storage, segments[0], params, headers)
  }
  if (segments[1] === 'info' || segments[1] === 'detail') {
    return handleGenericDetail(state, segments[0], segments[2])
  }
  if (segments[1] === 'save' || segments[1] === 'add') {
    return handleGenericSave(state, storage, segments[0], body)
  }
  if (segments[1] === 'update') {
    return handleGenericUpdate(state, storage, segments[0], body)
  }
  if (segments[1] === 'delete') {
    return handleGenericDelete(state, storage, segments[0], body)
  }

  return failure(`未实现的 mock 接口: ${normalized.path}`, 404)
}

export function createMockHttpClient(options) {
  const client = function (config) {
    return client.request(config)
  }

  client.headers = { common: {} }

  client.request = function (config) {
    const response = handleMockRequest(config, {
      storage: options && options.storage,
      headers: client.headers.common
    })
    return Promise.resolve({
      data: response,
      body: response,
      status: response.code === 0 ? 200 : response.code,
      ok: response.code === 0,
      config
    })
  }

  client.get = function (url, config) {
    return client.request(Object.assign({}, config || {}, {
      url,
      method: 'get'
    }))
  }

  client.post = function (url, data, config) {
    return client.request(Object.assign({}, config || {}, {
      url,
      method: 'post',
      data
    }))
  }

  return client
}
